201→    async fn identity_update(&self, params: Value) -> ServiceResult {
202→        let response = self
203→            .inner
204→            .identity_update(params)
205→            .map_err(ServiceError::message)?;
206→
207→        if let Some(state) = self.gateway_state.get()
208→            && let Some(location_value) = response.get("user_location")
209→        {
210→            let mut inner = state.inner.write().await;
211→            if location_value.is_null() {
212→                inner.cached_location = None;
213→            } else if let Some(location) = parse_geo_location(location_value) {
214→                inner.cached_location = Some(location);
