293→    #[cfg(feature = "openclaw-import")]
294→    async fn openclaw_import(&self, params: Value) -> ServiceResult {
295→        let detection = moltis_openclaw_import::detect()
296→            .ok_or_else(|| "no OpenClaw installation found".to_string())?;
297→
298→        let selection = moltis_openclaw_import::ImportSelection {
299→            identity: params
300→                .get("identity")
301→                .and_then(|v| v.as_bool())
302→                .unwrap_or(false),
303→            providers: params
304→                .get("providers")
305→                .and_then(|v| v.as_bool())
306→                .unwrap_or(false),
307→            skills: params
308→                .get("skills")
309→                .and_then(|v| v.as_bool())
310→                .unwrap_or(false),
311→            memory: params
312→                .get("memory")
313→                .and_then(|v| v.as_bool())
314→                .unwrap_or(false),
315→            channels: params
316→                .get("channels")
317→                .and_then(|v| v.as_bool())
318→                .unwrap_or(false),
319→            sessions: params
320→                .get("sessions")
321→                .and_then(|v| v.as_bool())
322→                .unwrap_or(false),
323→            workspace_files: params
324→                .get("workspace_files")
325→                .and_then(|v| v.as_bool())
326→                .unwrap_or(false),
327→        };
328→
329→        let config_dir = moltis_config::config_dir()
330→            .ok_or_else(|| "could not determine config directory".to_string())?;
331→        let data_dir = moltis_config::data_dir();
332→
333→        let report = moltis_openclaw_import::import(&detection, &selection, &config_dir, &data_dir);
334→
335→        // Create imported agent personas (non-default agents)
336→        if let Some(ref agents) = report.imported_agents
337→            && let Err(e) = self.create_imported_agents(agents).await
338→        {
339→            tracing::warn!(error = %e, "openclaw import: failed to create imported agents");
340→        }
341→
342→        if selection.sessions
343→            && let Err(e) = self.sync_imported_sessions_to_sqlite(&data_dir).await
344→        {
345→            tracing::warn!(error = %e, "openclaw import: failed to sync sessions to sqlite metadata");
346→        }
347→
348→        // Ensure the default "main" session exists so it appears in the session
349→        // list alongside imported sessions. Without this, the main session only
350→        // gets created when the user sends their first message.
351→        if self.session_metadata.get("main").await.is_none()
352→            && let Err(e) = self
353→                .session_metadata
354→                .upsert("main", Some("Main".to_string()))
355→                .await
356→        {
357→            tracing::warn!(error = %e, "openclaw import: failed to ensure main session exists");
358→        }
359→
360→        Ok(serde_json::to_value(&report)?)
361→    }
