369→fn parse_geo_location(value: &Value) -> Option<moltis_config::GeoLocation> {
370→    let latitude = value.get("latitude").and_then(|v| v.as_f64())?;
371→    let longitude = value.get("longitude").and_then(|v| v.as_f64())?;
372→    let place = value
373→        .get("place")
374→        .and_then(|v| v.as_str())
375→        .map(|v| v.to_string());
376→    let updated_at = value.get("updated_at").and_then(|v| v.as_i64());
377→
378→    Some(moltis_config::GeoLocation {
379→        latitude,
380→        longitude,
381→        place,
382→        updated_at,
383→    })
384→}
