391→    #[test]
392→    fn parse_geo_location_parses_valid_payload() {
393→        let parsed = parse_geo_location(&serde_json::json!({
394→            "latitude": 40.7128,
395→            "longitude": -74.0060,
396→            "place": "New York",
397→            "updated_at": 123,
398→        }))
399→        .expect("location should parse");
400→
401→        assert_eq!(parsed.latitude, 40.7128);
402→        assert_eq!(parsed.longitude, -74.0060);
403→        assert_eq!(parsed.place.as_deref(), Some("New York"));
404→        assert_eq!(parsed.updated_at, Some(123));
405→    }
406→
