1079→function sortProviders(list) {
1080→	list.sort((a, b) => {
1081→		var aOrder = Number.isFinite(a.uiOrder) ? a.uiOrder : Number.MAX_SAFE_INTEGER;
1082→		var bOrder = Number.isFinite(b.uiOrder) ? b.uiOrder : Number.MAX_SAFE_INTEGER;
1083→		if (aOrder !== bOrder) return aOrder - bOrder;
1084→		return a.displayName.localeCompare(b.displayName);
1085→	});
1086→	return list;
1087→}
