  7→/// Status of the local LLM provider.
  8→#[derive(Debug, Clone, Serialize)]
  9→#[serde(tag = "status", rename_all = "lowercase")]
 10→pub enum LocalLlmStatus {
 11→    /// No model configured.
 12→    Unconfigured,
 13→    /// Model configured but not yet loaded.
 14→    Ready { model_id: String },
 15→    /// Model is being downloaded/loaded.
 16→    Loading {
 17→        model_id: String,
 18→        progress: Option<f32>,
 19→    },
 20→    /// Model is loaded and ready.
 21→    Loaded { model_id: String },
 22→    /// Error loading model.
 23→    Error { model_id: String, error: String },
 24→    /// Feature not enabled.
 25→    Unavailable,
 26→}
