 81→fn gguf_acceleration_labels(sys: &local_gguf::system_info::SystemInfo) -> Vec<&'static str> {
 82→    let mut labels = Vec::new();
 83→    if sys.has_metal {
 84→        labels.push("Metal");
 85→    }
 86→    if sys.has_cuda {
 87→        labels.push("CUDA");
 88→    }
 89→    if sys.has_vulkan {
 90→        labels.push("Vulkan");
 91→    }
 92→    labels
 93→}
