 95→fn gguf_acceleration_name(sys: &local_gguf::system_info::SystemInfo) -> Option<String> {
 96→    let labels = gguf_acceleration_labels(sys);
 97→    if labels.is_empty() {
 98→        None
 99→    } else {
100→        Some(labels.join("/"))
101→    }
102→}
