104→pub(super) fn gguf_backend_description(sys: &local_gguf::system_info::SystemInfo) -> String {
105→    match gguf_acceleration_name(sys) {
106→        Some(acceleration) => format!("Cross-platform, {acceleration} GPU acceleration"),
107→        None if sys.has_gpu() => "Cross-platform, GPU acceleration".to_string(),
108→        None => "Cross-platform, CPU inference".to_string(),
109→    }
110→}
