238→        let model_id = params
239→            .get("modelId")
240→            .and_then(|v| v.as_str())
241→            .ok_or_else(|| "missing 'modelId' parameter".to_string())?
242→            .to_string();
243→
244→        // Get backend choice (default to recommended)
245→        let sys = local_gguf::system_info::SystemInfo::detect();
246→        let mlx_available = sys.is_apple_silicon && is_mlx_installed();
247→        let default_backend = if mlx_available {
248→            "MLX"
249→        } else {
250→            "GGUF"
251→        };
252→        let backend = params
253→            .get("backend")
254→            .and_then(|v| v.as_str())
255→            .unwrap_or(default_backend)
256→            .to_string();
257→
258→        // Validate backend choice
259→        if backend != "GGUF" && backend != "MLX" {
260→            return Err(format!("invalid backend: {backend}. Must be GGUF or MLX").into());
261→        }
262→        if backend == "MLX" && !mlx_available {
263→            return Err("MLX backend requires mlx-lm. Install with: pip install mlx-lm".into());
264→        }
265→
266→        // Validate model exists in registry
267→        let model_def = local_gguf::models::find_model(&model_id)
268→            .ok_or_else(|| format!("unknown model: {model_id}"))?;
269→
270→        let total_ram_gb = sys.total_ram_gb();
271→        if !has_enough_ram(total_ram_gb, model_def.min_ram_gb) {
272→            return Err(insufficient_ram_error(
273→                model_def.display_name,
274→                model_def.min_ram_gb,
275→                total_ram_gb,
276→            )
277→            .into());
278→        }
279→
280→        info!(model = %model_id, backend = %backend, "configuring local-llm");
281→
282→        // Update status to loading
283→        {
284→            let mut status = self.status.write().await;
285→            *status = LocalLlmStatus::Loading {
286→                model_id: model_id.clone(),
287→                progress: None,
288→            };
289→        }
290→
291→        // Save configuration (add to existing models)
