 21→impl LiveProviderSetupService {
 22→    pub(super) async fn available_inner(&self) -> ServiceResult {
 23→        let is_cloud = self.deploy_platform.is_some();
 24→        let active_config = self.config_snapshot();
 25→        let offered_order = ui_offered_provider_order(&active_config);
 26→        let offered = ui_offered_provider_set(&offered_order);
 27→        let offered_rank: HashMap<String, usize> = offered_order
 28→            .iter()
 29→            .enumerate()
 30→            .map(|(idx, provider)| (provider.clone(), idx))
 31→            .collect();
 32→
 33→        let mut providers: Vec<(Option<usize>, usize, Value)> = known_providers()
 34→            .iter()
 35→            .enumerate()
 36→            .filter_map(|(known_idx, provider)| {
 37→                // Hide local-only providers on cloud deployments.
 38→                if is_cloud && provider.is_local_only() {
 39→                    return None;
 40→                }
 41→
 42→                let configured = self.is_provider_configured(provider, &active_config);
 43→                let normalized_name = normalize_provider_name(provider.name);
 44→                if let Some(allowed) = offered.as_ref()
 45→                    && !allowed.contains(&normalized_name)
 46→                    && !configured
 47→                {
 48→                    return None;
 49→                }
 50→
 51→                // Get saved config for this provider (baseUrl, preferred models)
 52→                let saved_config = self.key_store.load_config(provider.name);
 53→                let base_url = saved_config.as_ref().and_then(|c| c.base_url.clone());
 54→                let models = saved_config
 55→                    .map(|c| normalize_model_list(c.models))
 56→                    .unwrap_or_default();
 57→                let model = models.first().cloned();
 58→
 59→                Some((
 60→                    offered_rank.get(&normalized_name).copied(),
 61→                    known_idx,
 62→                    serde_json::json!({
 63→                        "name": provider.name,
 64→                        "displayName": provider.display_name,
 65→                        "authType": provider.auth_type.as_str(),
 66→                        "configured": configured,
 67→                        "defaultBaseUrl": provider.default_base_url,
 68→                        "baseUrl": base_url,
 69→                        "models": models,
 70→                        "model": model,
 71→                        "requiresModel": provider.requires_model,
 72→                        "keyOptional": provider.key_optional,
 73→                    }),
 74→                ))
 75→            })
 76→            .collect();
 77→
 78→        // Append custom providers from the key store.
 79→        let known_count = providers.len();
 80→        for (name, config) in self.key_store.load_all_configs() {
 81→            if !is_custom_provider(&name) {
 82→                continue;
 83→            }
 84→            if active_config.get(&name).is_some_and(|entry| !entry.enabled) {
 85→                continue;
 86→            }
 87→            let display_name = config.display_name.clone().unwrap_or_else(|| name.clone());
 88→            let base_url = config.base_url.clone();
 89→            let models = normalize_model_list(config.models.clone());
 90→            let model = models.first().cloned();
 91→
 92→            providers.push((
 93→                None,
 94→                known_count, // sort after all known providers
 95→                serde_json::json!({
 96→                    "name": name,
 97→                    "displayName": display_name,
 98→                    "authType": "api-key",
 99→                    "configured": true,
100→                    "defaultBaseUrl": base_url,
101→                    "baseUrl": base_url,
102→                    "models": models,
103→                    "model": model,
104→                    "requiresModel": true,
105→                    "keyOptional": false,
106→                    "isCustom": true,
107→                }),
108→            ));
109→        }
110→
111→        providers.sort_by(
112→            |(a_offered, a_known, a_value), (b_offered, b_known, b_value)| {
113→                let offered_cmp = match (a_offered, b_offered) {
114→                    (Some(a), Some(b)) => a.cmp(b),
115→                    (Some(_), None) => std::cmp::Ordering::Less,
116→                    (None, Some(_)) => std::cmp::Ordering::Greater,
117→                    (None, None) => std::cmp::Ordering::Equal,
118→                };
119→                if offered_cmp != std::cmp::Ordering::Equal {
120→                    return offered_cmp;
121→                }
122→
123→                let known_cmp = a_known.cmp(b_known);
124→                if known_cmp != std::cmp::Ordering::Equal {
125→                    return known_cmp;
126→                }
127→
128→                let a_name = a_value
129→                    .get("displayName")
130→                    .and_then(|v| v.as_str())
131→                    .unwrap_or_default();
132→                let b_name = b_value
133→                    .get("displayName")
134→                    .and_then(|v| v.as_str())
135→                    .unwrap_or_default();
136→                a_name.cmp(b_name)
137→            },
138→        );
139→
140→        let providers: Vec<Value> = providers
141→            .into_iter()
142→            .enumerate()
143→            .map(|(idx, (_, _, mut value))| {
144→                if let Some(obj) = value.as_object_mut() {
145→                    obj.insert("uiOrder".into(), serde_json::json!(idx));
146→                }
147→                value
148→            })
149→            .collect();
150→
151→        Ok(Value::Array(providers))
152→    }
153→}
